    int latestTimeCatchTheBus(vector<int>& buses, vector<int>& passengers, int capacity) {
        sort(buses.begin(), buses.end());
        sort(passengers.begin(), passengers.end());
        int latestTime = 0;
        int busIndex = 0;
        int passengerIndex = 0;
        while (passengerIndex < passengers.size()) {
            if (buses[busIndex] == passengers[passengerIndex]) {
                passengerIndex++;
                busIndex++;
            } else if (buses[busIndex] > passengers[passengerIndex]) {
                latestTime = max(latestTime, buses[busIndex] - 1);
                busIndex++;
            } else {
                int count = 0;
                while (passengerIndex < passengers.size() && count < capacity) {
                    if (buses[busIndex] >= passengers[passengerIndex]) {
                        count++;
                        passengerIndex++;
                    } else {
                        break;
                    }
                }
                busIndex++;
            }
        }
        return latestTime;
    }
};
